				const elapsed = Date.now() - startTime;
				if (this.loadGeneration !== generation) {
					this.debug(`startBackgroundLoad: stale gen=${generation} (current=${this.loadGeneration}), discarding ${cards.length} cards after ${elapsed}ms`);
