	refresh(): void {
		this.debug(`refresh: loadState=${this.loadState.kind}`);
		this.changeEmitter.fire();
	}

	/**
	 * Forces the tree into a visible loading state without starting a data read.
	 * Used by manual refresh so the UI reflects in-progress remote sync work.
	 */
	showLoading(): void {
		this.loadGeneration++;
		this.loadState = { kind: "loading" };
		this.debug(`showLoading: gen=${this.loadGeneration}`);
		this.changeEmitter.fire();
	}

	/**
	 * Full reload: discard cached cards and spawn CLI processes to
