function isPromiseLike<T>(value: unknown): value is PromiseLike<T> {
	return typeof value === "object" && value !== null && "then" in value && typeof (value as { then?: unknown }).then === "function";
}

async function getChildren(
	provider: CheckpointTreeViewProvider,
	element?: vscode.TreeItem,
): Promise<vscode.TreeItem[]> {
	const result = await Promise.resolve(provider.getChildren(element));
	return result ?? [];
}

function createCheckpointCommands(): CheckpointViewCommands {
	return {
		refresh: "session.bridge.entire.refresh",
		openCommitChanges: "session.bridge.entire.openCommitChanges",
	};
}

getChildren(element?: vscode.TreeItem): vscode.ProviderResult<vscode.TreeItem[]> {
	if (element instanceof ToplevelCheckpointTreeItem) {
		return buildCommitCheckpointItems(element.card.checkpointCommits, this.commands);
	}

	if (element instanceof CheckpointTreeItem) {
		return buildChildItems(element.card, this.commands, this.repoPath);
	}

	if (this.workspaceState.state !== EntireStatusState.ENABLED) {
		this.debug(`getChildren: disabled state=${this.workspaceState.state}`);
		return [];
	}

	if (!this.repoPath) {
		this.debug("getChildren: no repoPath");
		return [];
	}

	if (this.pendingRootLoad) {
		return this.pendingRootLoad.then(() => this.buildRootItems());
	}

	this.debug(`getChildren: loadState=${this.loadState.kind}${this.loadState.kind === "loaded" ? `, cards=${this.loadState.cards.length}` : ""}${this.loadState.kind === "error" ? `, error=${this.loadState.message}` : ""}`);

	switch (this.loadState.kind) {
		case "ready":
			this.debug(`getChildren: auto-starting initial load, gen=${this.loadGeneration}, repoPath=${this.repoPath}`);
			return this.queueRootLoad(this.repoPath).then(() => this.buildRootItems());

		case "error":
			return this.buildRootItems();

		case "loaded": {
			return this.buildRootItems();
		}
	}
}

/**
 * Runs checkpoint summary loading in the background while allowing VS Code
 * to show its native tree progress UI for the pending getChildren request.
 */
private queueRootLoad(
	repoPath: string,
	after: Promise<void> = Promise.resolve(),
	force = false,
): Promise<CheckpointDateGroup[]> {
